        let numBackspaces = currentRendered.count - diverge
        let replacementChars = Array(next.suffix(from: diverge))

        // Emit backspaces
        for _ in 0..<numBackspaces {
            if let down = CGEvent(keyboardEventSource: source, virtualKey: 0x33, keyDown: true),
